// ============================================================
// BUILD TIMELINE → produces full render payload
// ============================================================
// Takes input data and builds the Remotion API body.
//
// Expected input:
//   images: [{ src, start, length, effect }]  // or single imageUrl
//   texts:  [{ text, start, length, vertical, horizontal, fontSize }]
//   audios: [{ src, start, length }]
//   soundtrack: { src, volume }  // or soundtrackUrl string
//   resolution: "1080"
//   fps: 25
//
// All optional — sensible defaults fill in the gaps.

const input = $input.first().json;

const images = (input.images && input.images.length)
  ? input.images
  : [{ src: input.imageUrl || 'https://images.unsplash.com/photo-1462331940025-496dfbfc7564?w=1920&h=1080&fit=crop' }];

const texts = (input.texts && input.texts.length)
  ? input.texts
  : (input.caption ? [{ text: input.caption }] : []);

const audios = (input.audios && input.audios.length) ? input.audios : [];

// Calculate total duration from longest clip
const totalDur = [...images, ...texts, ...audios].reduce((max, c) =>
  Math.max(max, (c.start ?? 0) + (c.length ?? 5)), 0
) || 5;

const tracks = [];

// Track 1: Images (with optional Ken Burns effects)
if (images.length) {
  tracks.push({
    clips: images.map(img => {
      const clip = {
        asset: { type: 'image', src: img.src },
        start: img.start ?? 0,
        length: img.length ?? totalDur,
        fit: img.fit || 'cover'
      };
      if (img.effect) clip.effect = img.effect;
      const fadeIn = img.fadeIn || img.transition?.in === 'fade';
      const fadeOut = img.fadeOut || img.transition?.out === 'fade';
      if (fadeIn || fadeOut) {
        clip.transition = {};
        if (fadeIn) clip.transition.in = 'fade';
        if (fadeOut) clip.transition.out = 'fade';
      }
      return clip;
    })
  });
}

// Track 2: Text overlays (use alignment.vertical for position!)
if (texts.length) {
  tracks.push({
    clips: texts.map(txt => ({
      asset: {
        type: 'text',
        text: txt.text || '',
        font: {
          family: txt.fontFamily || 'Inter',
          size: txt.fontSize || 36,
          color: txt.fontColor || '#FFFFFF',
          weight: txt.fontWeight || 400
        },
        alignment: {
          horizontal: txt.horizontal || 'center',
          vertical: txt.vertical || 'bottom'  // ← this is what positions it!
        },
        background: txt.background || 'rgba(0,0,0,0.3)'
      },
      start: txt.start ?? 0,
      length: txt.length ?? totalDur
    }))
  });
}

// Track 3: Scene audio clips
if (audios.length) {
  tracks.push({
    clips: audios.map(a => ({
      asset: { type: 'audio', src: a.src },
      start: a.start ?? 0,
      length: a.length ?? totalDur
    }))
  });
}

const timeline = { tracks };

// Soundtrack (background audio plays full duration)
const soundtrackSrc = input.soundtrack?.src || input.soundtrackUrl;
if (soundtrackSrc) {
  timeline.soundtrack = {
    src: soundtrackSrc,
    volume: input.soundtrack?.volume ?? 0.15
  };
}

// Return full payload — HTTP node will POST this as-is
return {
  timeline: timeline,
  output: {
    format: 'mp4',
    resolution: input.resolution || '1080',
    fps: input.fps || 25
  }
};

// ============================================================
// POLL until render is done (handles the full wait loop)
// ============================================================
// Remotion renders async — POST returns immediately with an ID.
// This node polls GET /edit/v1/render/:id every 2 seconds
// until status is "done" or we hit maxAttempts.

const axios = require('axios');

const renderResponse = $input.first().json;

if (!renderResponse.success) {
  throw new Error('Render API error: ' + JSON.stringify(renderResponse));
}

const renderId = renderResponse.response.id;
const pollUrl = 'http://remotion:3000/edit/v1/render/' + renderId;
const maxAttempts = 150;  // 150 polls × 2s = 5 min max

for (let i = 0; i < maxAttempts; i++) {
  // Wait 2 seconds between polls
  await new Promise(resolve => setTimeout(resolve, 2000));

  const resp = await axios.get(pollUrl);
  const data = resp.data;

  if (!data.success) {
    throw new Error('Poll failed: ' + JSON.stringify(data));
  }

  const status = data.response.status;

  if (status === 'done') {
    return {
      renderId: renderId,
      status: 'done',
      videoUrl: 'http://remotion:3000' + data.response.url,
      pollsNeeded: i + 1
    };
  }

  if (status === 'failed') {
    throw new Error('Render failed: ' + (data.response.error || 'unknown error'));
  }
}

throw new Error('Render timed out after ' + maxAttempts + ' polls (' + renderId + ')');

// ============================================================
// OUTPUT — Video is ready!
// ============================================================
// Use $json.videoUrl to download the MP4
//
// Connect downstream nodes here:
//   - HTTP Request to download the file
//   - Google Drive / Telegram / YouTube to publish
//   - Or pass to next step

const result = $input.first().json;

return {
  renderId: result.renderId,
  status: 'done',
  videoUrl: result.videoUrl,
  message: 'Render complete! Took ' + result.pollsNeeded + ' polls',
  // Download URL (use with HTTP Request node set to GET with Response Format: File)
  downloadUrl: result.videoUrl
};
